// FanOutTask enqueues child tasks for the same issue under a parent task.
// Child tasks reuse the existing queue/claim model but can run in parallel
// when they share the same parent_task_id.
func (s *TaskService) FanOutTask(ctx context.Context, parentTaskID, issueID pgtype.UUID, specs []FanOutTaskSpec) ([]db.AgentTaskQueue, error) {
	if len(specs) == 0 {
		return nil, fmt.Errorf("at least one fan-out task is required")
	}

	parentTask, err := s.Queries.GetAgentTask(ctx, parentTaskID)
	if err != nil {
		return nil, fmt.Errorf("load parent task: %w", err)
	}
	if parentTask.IssueID != issueID {
		return nil, fmt.Errorf("parent task does not belong to issue")
	}

	issue, err := s.Queries.GetIssue(ctx, issueID)
	if err != nil {
		return nil, fmt.Errorf("load issue: %w", err)
	}

	queued := make([]db.AgentTaskQueue, 0, len(specs))
	seenAgents := map[string]struct{}{}
	for _, spec := range specs {
		agentKey := util.UUIDToString(spec.AgentID)
		if _, exists := seenAgents[agentKey]; exists {
			return nil, fmt.Errorf("fan-out does not allow duplicate agent_id %s in the same request", agentKey)
		}
		seenAgents[agentKey] = struct{}{}

		mode := NormalizeTaskMode(spec.Mode)
		agentRecord, err := s.Queries.GetAgent(ctx, spec.AgentID)
		if err != nil {
			return nil, fmt.Errorf("load agent: %w", err)
		}
		if agentRecord.ArchivedAt.Valid {
			return nil, fmt.Errorf("agent is archived")
		}
		if !agentRecord.RuntimeID.Valid {
			return nil, fmt.Errorf("agent has no runtime")
		}
		if err := ValidateRuntimeExecutionModeSupport(ctx, s.Queries, agentRecord.RuntimeID, mode); err != nil {
			return nil, err
		}

		task, err := s.Queries.CreateAgentTask(ctx, db.CreateAgentTaskParams{
			AgentID:       spec.AgentID,
			RuntimeID:     agentRecord.RuntimeID,
			IssueID:       issue.ID,
			Priority:      priorityToInt(issue.Priority),
			Mode:          mode,
			TriggerSource: TaskTriggerSourceSwarm,
			ParentTaskID:  parentTaskID,
			SwarmRole:     strings.TrimSpace(spec.Role),
		})
		if err != nil {
			return nil, fmt.Errorf("create child task: %w", err)
		}
		queued = append(queued, task)
		slog.Info("fan-out task enqueued",
			"task_id", util.UUIDToString(task.ID),
			"parent_task_id", util.UUIDToString(parentTaskID),
			"issue_id", util.UUIDToString(issue.ID),
			"agent_id", util.UUIDToString(spec.AgentID),
			"mode", mode,
			"role", strings.TrimSpace(spec.Role),
		)
	}

	if _, _, err := s.setIssueExecutionStage(ctx, issue, QueueStageForMode(specs[0].Mode)); err != nil {
		slog.Warn("fan-out: failed to update execution stage", "issue_id", util.UUIDToString(issue.ID), "error", err)
	}

	return queued, nil
}

// CancelTasksForIssue cancels all active tasks for an issue.
func (s *TaskService) CancelTasksForIssue(ctx context.Context, issueID pgtype.UUID) error {
	return s.Queries.CancelAgentTasksByIssue(ctx, issueID)
}

// CancelTask cancels a single task by ID. It broadcasts a task:cancelled event
// so frontends can update immediately.
func (s *TaskService) CancelTask(ctx context.Context, taskID pgtype.UUID) (*db.AgentTaskQueue, error) {
	task, err := s.Queries.CancelAgentTask(ctx, taskID)
	if err != nil {

		writeError(w, http.StatusInternalServerError, "failed to claim task: "+err.Error())
		return
	}

	if task == nil {
		slog.Debug("no task to claim", "runtime_id", runtimeID)
		writeJSON(w, http.StatusOK, map[string]any{"task": nil})
		return
	}

	// Build response with fresh agent data (name + skills).
	resp := taskToResponse(*task)
	if agent, err := h.Queries.GetAgent(r.Context(), task.AgentID); err == nil {
		skills := h.TaskService.LoadAgentSkills(r.Context(), task.AgentID)
		resp.Agent = &TaskAgentData{
			ID:           uuidToString(agent.ID),
			Name:         agent.Name,
			Instructions: agent.Instructions,
			Skills:       skills,
		}
	}

	// Include workspace ID and repos so the daemon can set up worktrees.
	if issue, err := h.Queries.GetIssue(r.Context(), task.IssueID); err == nil {
		resp.WorkspaceID = uuidToString(issue.WorkspaceID)
		if memories, err := h.Queries.ListRecentRunMemoryByIssue(r.Context(), db.ListRecentRunMemoryByIssueParams{
			IssueID: task.IssueID,
			Limit:   5,
		}); err == nil && len(memories) > 0 {
			resp.Memories = make([]RunMemoryResponse, len(memories))
			for i, memory := range memories {
				resp.Memories[i] = RunMemoryResponse{
					ID:        uuidToString(memory.ID),
					Kind:      memory.Kind,
					Title:     memory.Title,
					Content:   memory.Content,
					CreatedAt: timestampToString(memory.CreatedAt),
				}
			}
		}
		if issue.RepoUrl.Valid {
			resp.SelectedRepoURL = issue.RepoUrl.String
		}
		if ws, err := h.Queries.GetWorkspace(r.Context(), issue.WorkspaceID); err == nil && ws.Repos != nil {
			var repos []RepoData
			if json.Unmarshal(ws.Repos, &repos) == nil && len(repos) > 0 {
				resp.Repos = repos
				for _, repo := range repos {
					if repo.URL == issue.RepoUrl.String {
						resp.SelectedRepoDescription = repo.Description
						break
					}
				}
			}
		}
		if issue.IdeaID.Valid {
			if idea, err := h.IdeaStore.GetIdeaByID(r.Context(), h.DB, uuidToString(issue.IdeaID)); err == nil {
				resp.IdeaSlug = idea.SlugFull
				resp.IdeaCode = idea.Code
				resp.IdeaTitle = idea.Title
				if resp.SelectedRepoURL == "" {
					resp.SelectedRepoURL = idea.ProjectRepoURL
					resp.SelectedRepoDescription = "Idea project repository"
				}
			}
		}
	}

	// Look up the prior session for this (agent, issue) pair so the daemon
	// can resume the Claude Code conversation context.
	if prior, err := h.Queries.GetLastTaskSession(r.Context(), db.GetLastTaskSessionParams{
		AgentID: task.AgentID,
		IssueID: task.IssueID,
	}); err == nil && prior.SessionID.Valid {
		resp.PriorSessionID = prior.SessionID.String
		if prior.WorkDir.Valid {
			resp.PriorWorkDir = prior.WorkDir.String
		}
	}

	slog.Info("task claimed by runtime", "task_id", uuidToString(task.ID), "runtime_id", runtimeID, "agent_id", uuidToString(task.AgentID), "prior_session", resp.PriorSessionID)
	writeJSON(w, http.StatusOK, map[string]any{"task": resp})
}

// ListPendingTasksByRuntime returns queued/dispatched tasks for a runtime.
func (h *Handler) ListPendingTasksByRuntime(w http.ResponseWriter, r *http.Request) {
	runtimeID := chi.URLParam(r, "runtimeId")

	tasks, err := h.Queries.ListPendingTasksByRuntime(r.Context(), parseUUID(runtimeID))
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to list pending tasks")
		return
	}

	resp := make([]AgentTaskResponse, len(tasks))
	for i, t := range tasks {
		resp[i] = taskToResponse(t)
	}

	writeJSON(w, http.StatusOK, resp)
}

// ---------------------------------------------------------------------------
// Task Lifecycle (called by daemon)
// ---------------------------------------------------------------------------

// StartTask marks a dispatched task as running.
func (h *Handler) StartTask(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")

	task, err := h.TaskService.StartTask(r.Context(), parseUUID(taskID))
	if err != nil {
		slog.Warn("start task failed", "task_id", taskID, "error", err)
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	slog.Info("task started", "task_id", taskID, "agent_id", uuidToString(task.AgentID))
	writeJSON(w, http.StatusOK, taskToResponse(*task))
}

// ReportTaskProgress broadcasts a progress update.
type TaskProgressRequest struct {
	Summary string `json:"summary"`
	Step    int    `json:"step"`
	Total   int    `json:"total"`
}

func (h *Handler) ReportTaskProgress(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")

	var req TaskProgressRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}

	// Look up task to get workspace ID via the associated issue.
	workspaceID := ""
	task, err := h.Queries.GetAgentTask(r.Context(), parseUUID(taskID))
	if err == nil {
		if issue, err := h.Queries.GetIssue(r.Context(), task.IssueID); err == nil {
			workspaceID = uuidToString(issue.WorkspaceID)
		}
	}

	h.TaskService.ReportProgress(r.Context(), taskID, workspaceID, req.Summary, req.Step, req.Total)
	writeJSON(w, http.StatusOK, map[string]string{"status": "ok"})
}

// CompleteTask marks a running task as completed.
type TaskCompleteRequest struct {
	PRURL                string   `json:"pr_url"`
	CompareURL           string   `json:"compare_url"`
	BranchName           string   `json:"branch_name"`
	Output               string   `json:"output"`
	Summary              string   `json:"summary"`
	DeliveryState        string   `json:"delivery_state"`
	HandoffReason        string   `json:"handoff_reason"`
	PlanStatus           string   `json:"plan_status"`
	PlanRequiresDecision bool     `json:"plan_requires_decision"`
	PlanQuestions        []string `json:"plan_questions"`
	SessionID            string   `json:"session_id"` // Claude session ID for future resumption
	WorkDir              string   `json:"work_dir"`   // working directory used during execution
}

func (h *Handler) CompleteTask(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")

	var req TaskCompleteRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}

	result, _ := json.Marshal(req)
	task, err := h.TaskService.CompleteTask(r.Context(), parseUUID(taskID), result, req.SessionID, req.WorkDir)
	if err != nil {
		slog.Warn("complete task failed", "task_id", taskID, "error", err)
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	slog.Info("task completed", "task_id", taskID, "agent_id", uuidToString(task.AgentID))
	writeJSON(w, http.StatusOK, taskToResponse(*task))
}

// GetTaskStatus returns the current status of a task.
// Used by the daemon to check whether a task was cancelled mid-execution.
func (h *Handler) GetTaskStatus(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")
	task, err := h.Queries.GetAgentTask(r.Context(), parseUUID(taskID))
	if err != nil {
		writeError(w, http.StatusNotFound, "task not found")
		return
	}
	writeJSON(w, http.StatusOK, map[string]string{"status": task.Status})
}

// FailTask marks a running task as failed.
type TaskFailRequest struct {
	Error string `json:"error"`
}

func (h *Handler) FailTask(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")

	var req TaskFailRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}

	task, err := h.TaskService.FailTask(r.Context(), parseUUID(taskID), req.Error)
	if err != nil {
		slog.Warn("fail task failed", "task_id", taskID, "error", err)
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	slog.Info("task failed", "task_id", taskID, "agent_id", uuidToString(task.AgentID), "task_error", req.Error)
	writeJSON(w, http.StatusOK, taskToResponse(*task))
}

// ---------------------------------------------------------------------------
// Task Messages (live agent output)
// ---------------------------------------------------------------------------

type TaskMessageRequest struct {
	Seq      int            `json:"seq"`
	Type     string         `json:"type"`
	Tool     string         `json:"tool,omitempty"`
	Content  string         `json:"content,omitempty"`
	Input    map[string]any `json:"input,omitempty"`
	Output   string         `json:"output,omitempty"`
	Metadata map[string]any `json:"metadata,omitempty"`
}

type TaskMessageBatchRequest struct {
	Messages []TaskMessageRequest `json:"messages"`
}

// ReportTaskMessages receives a batch of agent execution messages from the daemon.
func (h *Handler) ReportTaskMessages(w http.ResponseWriter, r *http.Request) {
	taskID := chi.URLParam(r, "taskId")

	var req TaskMessageBatchRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}
	if len(req.Messages) == 0 {
		writeJSON(w, http.StatusOK, map[string]string{"status": "ok"})
		return
	}

	task, err := h.Queries.GetAgentTask(r.Context(), parseUUID(taskID))
	if err != nil {
		writeError(w, http.StatusNotFound, "task not found")
		return
	}

