// writeContextFiles renders and writes .agent_context/issue_context.md and
// skills into the appropriate provider-native location.
//
// Claude:   skills → {workDir}/.claude/skills/{name}/SKILL.md  (native discovery)
// Codex:    skills → handled separately in Prepare via codex-home
// OpenCode: skills → {workDir}/.config/opencode/skills/{name}/SKILL.md  (native discovery)
// Trae:     skills → {workDir}/.agent_context/skills/{name}/SKILL.md
// Default:  skills → {workDir}/.agent_context/skills/{name}/SKILL.md
func writeContextFiles(workDir, provider string, ctx TaskContextForEnv) error {
	contextDir := filepath.Join(workDir, ".agent_context")
	if err := os.MkdirAll(contextDir, 0o755); err != nil {
		return fmt.Errorf("create .agent_context dir: %w", err)
	}

	content := renderIssueContext(provider, ctx)
	path := filepath.Join(contextDir, "issue_context.md")
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		return fmt.Errorf("write issue_context.md: %w", err)
	}
	if err := writePolicyFile(workDir, ctx); err != nil {
		return fmt.Errorf("write policy.json: %w", err)
	}

	if len(ctx.AgentSkills) > 0 {
		// Codex and Hermes skills are written to provider home dirs in Prepare; skip here.
		if provider != "codex" && provider != "hermes" {
			skillsDir, err := resolveSkillsDir(workDir, provider)
			if err != nil {
				return fmt.Errorf("resolve skills dir: %w", err)
			}
			if err := writeSkillFiles(skillsDir, ctx.AgentSkills); err != nil {
				return fmt.Errorf("write skill files: %w", err)
			}
		}
	}

	return nil
}

// resolveSkillsDir returns the directory where skills should be written
// based on the agent provider.
func resolveSkillsDir(workDir, provider string) (string, error) {
	var skillsDir string
	switch provider {
	case "claude":
		// Claude Code natively discovers skills from .claude/skills/ in the workdir.
		skillsDir = filepath.Join(workDir, ".claude", "skills")
	case "opencode":
		// OpenCode natively discovers skills from .config/opencode/skills/ in the workdir.
		skillsDir = filepath.Join(workDir, ".config", "opencode", "skills")
	default:
		// Fallback: write to .agent_context/skills/ (referenced by meta config).
		skillsDir = filepath.Join(workDir, ".agent_context", "skills")
	}
	if err := os.MkdirAll(skillsDir, 0o755); err != nil {
		return "", err
	}
	return skillsDir, nil
}

var nonAlphaNum = regexp.MustCompile(`[^a-z0-9]+`)

// sanitizeSkillName converts a skill name to a safe directory name.
func sanitizeSkillName(name string) string {
	s := strings.ToLower(strings.TrimSpace(name))
	s = nonAlphaNum.ReplaceAllString(s, "-")
	s = strings.Trim(s, "-")
	if s == "" {
		s = "skill"
	}
	return s
}

// writeSkillFiles writes skill directories into the given parent directory.
// Each skill gets its own subdirectory containing SKILL.md and supporting files.
func writeSkillFiles(skillsDir string, skills []SkillContextForEnv) error {
	if err := os.MkdirAll(skillsDir, 0o755); err != nil {
		return fmt.Errorf("create skills dir: %w", err)
	}

	for _, skill := range skills {
		dir := filepath.Join(skillsDir, sanitizeSkillName(skill.Name))
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return err
		}

		// Write main SKILL.md
		if err := os.WriteFile(filepath.Join(dir, "SKILL.md"), []byte(skill.Content), 0o644); err != nil {
			return err
		}

		// Write supporting files
		for _, f := range skill.Files {
			fpath := filepath.Join(dir, f.Path)
			if err := os.MkdirAll(filepath.Dir(fpath), 0o755); err != nil {
				return err
			}
			if err := os.WriteFile(fpath, []byte(f.Content), 0o644); err != nil {
				return err
			}
		}
	}

	return nil
}

// renderIssueContext builds the markdown content for issue_context.md.
func renderIssueContext(provider string, ctx TaskContextForEnv) string {
	var b strings.Builder

	b.WriteString("# Task Assignment\n\n")
	fmt.Fprintf(&b, "**Issue ID:** %s\n\n", ctx.IssueID)
	fmt.Fprintf(&b, "**Execution Mode:** %s\n\n", strings.ToUpper(strings.TrimSpace(ctx.Mode)))
	if ctx.ParentTaskID != "" || ctx.SwarmRole != "" {
		b.WriteString("## Swarm Context\n\n")
		if ctx.ParentTaskID != "" {
			fmt.Fprintf(&b, "**Parent Task ID:** %s\n\n", ctx.ParentTaskID)
		}
		if ctx.SwarmRole != "" {
			fmt.Fprintf(&b, "**Role:** %s\n\n", ctx.SwarmRole)
		}
	}

	if ctx.TriggerCommentID != "" {
		b.WriteString("**Trigger:** Comment Reply\n")
		b.WriteString("**Triggering comment ID:** `" + ctx.TriggerCommentID + "`\n\n")
	} else {
		b.WriteString("**Trigger:** New Assignment\n\n")
	}

	b.WriteString("## Quick Start\n\n")
	fmt.Fprintf(&b, "Run `multica issue get %s --output json` to fetch the full issue details.\n\n", ctx.IssueID)
	if ctx.IdeaSlug != "" {
		fmt.Fprintf(&b, "Run `multica idea get %s --output json` to fetch the full idea document.\n\n", ctx.IdeaSlug)
	}
	if ctx.SelectedRepoURL != "" {
		b.WriteString("## Preferred Repository\n\n")
		fmt.Fprintf(&b, "- URL: %s\n", ctx.SelectedRepoURL)
		if ctx.SelectedRepoDescription != "" {
			fmt.Fprintf(&b, "- Description: %s\n", ctx.SelectedRepoDescription)
		}
		b.WriteString("\n")
	}

	if len(ctx.RunMemories) > 0 {
		b.WriteString("## Recent Run Memory\n\n")
		b.WriteString("Recent execution outcomes for this issue are available below. Use them to avoid repeating failed approaches and to preserve continuity.\n\n")
		for _, memory := range ctx.RunMemories {
			title := strings.TrimSpace(memory.Title)
			if title == "" {
				title = memory.Kind
			}
			fmt.Fprintf(&b, "### %s\n\n", title)
			if memory.CreatedAt != "" {
				fmt.Fprintf(&b, "- Created At: %s\n", memory.CreatedAt)
			}
			if memory.Kind != "" {
				fmt.Fprintf(&b, "- Kind: %s\n", memory.Kind)
			}
			b.WriteString("\n")
			b.WriteString(strings.TrimSpace(memory.Content))
			b.WriteString("\n\n")
		}
	}

	if len(ctx.AgentSkills) > 0 {
		b.WriteString("## Agent Skills\n\n")
		b.WriteString("The following skills are available to you:\n\n")
		for _, skill := range ctx.AgentSkills {
			fmt.Fprintf(&b, "- **%s**\n", skill.Name)
		}
		b.WriteString("\n")
	}

	return b.String()
}

package agent

import "fmt"

// Capabilities describes the runtime features exposed by an agent adapter.
// The daemon publishes these as runtime metadata so orchestration can make
// capability-aware decisions without hard-coding provider checks.
type Capabilities struct {
	StructuredStream bool `json:"structured_stream"`
	NativeResume     bool `json:"native_resume"`
	NativePlanMode   bool `json:"native_plan_mode"`
	ApprovalCallback bool `json:"approval_callback"`
	TrajectoryFile   bool `json:"trajectory_file"`
	PtyOnly          bool `json:"pty_only"`
}

var capabilitiesByType = map[string]Capabilities{
	"claude": {
		StructuredStream: true,
		NativeResume:     true,
		NativePlanMode:   true,
		ApprovalCallback: true,
	},
	"codex": {
		StructuredStream: true,
		NativeResume:     true,
		ApprovalCallback: true,
	},
	"opencode": {
		StructuredStream: true,
		NativeResume:     true,
		NativePlanMode:   true,
	},
	"trae": {
		NativeResume:   true,
		NativePlanMode: true,
		TrajectoryFile: true,
	},
	"hermes": {},
}

// CapabilitiesFor returns the capability set for a supported provider.
func CapabilitiesFor(agentType string) (Capabilities, error) {
	caps, ok := capabilitiesByType[agentType]
	if !ok {
		return Capabilities{}, fmt.Errorf("unknown agent type: %q", agentType)
	}
	return caps, nil
}

package agent

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"
)

var defaultContainerPATH = []string{
	"/usr/local/sbin",
	"/usr/local/bin",
	"/usr/sbin",
	"/usr/bin",
	"/sbin",
	"/bin",
	"/app",
}

func validateExecutable(execPath string, sandbox SandboxConfig) error {
	if strings.TrimSpace(sandbox.Driver) == "docker" {
		if _, err := exec.LookPath("docker"); err != nil {
			return fmt.Errorf("docker executable not found: %w", err)
		}
		return nil
	}
	if _, err := exec.LookPath(execPath); err != nil {
		return fmt.Errorf("executable not found at %q: %w", execPath, err)
	}
	return nil
}

func buildCommand(ctx context.Context, execPath string, args []string, cwd string, extraEnv map[string]string, sandbox SandboxConfig) (*exec.Cmd, error) {
	switch strings.TrimSpace(sandbox.Driver) {
	case "", "host":
		cmd := exec.CommandContext(ctx, execPath, args...)
		if cwd != "" {
			cmd.Dir = cwd
		}
		cmd.Env = buildEnv(extraEnv)
		return cmd, nil
	case "docker":
		image := strings.TrimSpace(sandbox.Image)
		if image == "" {
			return nil, fmt.Errorf("docker sandbox requires an image")
		}
		dockerEnv := sanitizeDockerEnv(extraEnv)

		dockerArgs := []string{
			"run", "--rm", "-i",
			"--cap-drop=ALL",
			"--security-opt=no-new-privileges",
			"--tmpfs", "/tmp:rw,noexec,nosuid,size=512m",
		}
		networkMode := strings.TrimSpace(sandbox.NetworkMode)
		if networkMode == "" {
			networkMode = "host"
		}
		if strings.TrimSpace(dockerEnv["MULTICA_DAEMON_PORT"]) != "" {
			networkMode = "host"
		}
		dockerArgs = append(dockerArgs, "--network", networkMode)

		for _, mount := range collectMountPaths(cwd, dockerEnv) {
			dockerArgs = append(dockerArgs, "-v", mount+":"+mount)
		}
		if cwd != "" {
			dockerArgs = append(dockerArgs, "-w", cwd)
		}
		for _, envEntry := range dockerEnvArgs(dockerEnv) {
			dockerArgs = append(dockerArgs, "-e", envEntry)
		}
		dockerArgs = append(dockerArgs, image, execPath)
		dockerArgs = append(dockerArgs, args...)

		cmd := exec.CommandContext(ctx, "docker", dockerArgs...)
		cmd.Env = buildEnv(nil)
		return cmd, nil
	default:
		return nil, fmt.Errorf("unsupported sandbox driver %q", sandbox.Driver)
	}
}

func collectMountPaths(cwd string, extraEnv map[string]string) []string {
	paths := map[string]struct{}{}
	addPath := func(raw string) {
		raw = strings.TrimSpace(raw)
		if raw == "" || !filepath.IsAbs(raw) {
			return
		}
		info, err := os.Stat(raw)
		if err != nil {
			return
		}
		mountPath := raw
		if !info.IsDir() {
			mountPath = filepath.Dir(raw)
		}
		if mountPath != "" {
			paths[mountPath] = struct{}{}
		}
	}

	addPath(cwd)
	for _, value := range extraEnv {
		if strings.Contains(value, string(os.PathListSeparator)) {
			for _, part := range filepath.SplitList(value) {
				if isDefaultContainerPath(part) {
					continue
				}
				addPath(part)
			}
			continue
		}
		addPath(value)
	}

	result := make([]string, 0, len(paths))
	for path := range paths {
		result = append(result, path)
	}
	sort.Strings(result)
	return result
}

func isDefaultContainerPath(path string) bool {
	path = strings.TrimSpace(path)
	for _, entry := range defaultContainerPATH {
		if path == entry {
			return true
		}
	}
	return false
}

func dockerEnvArgs(extraEnv map[string]string) []string {
	if len(extraEnv) == 0 {
		return nil
	}
	keys := make([]string, 0, len(extraEnv))
	for key := range extraEnv {
		keys = append(keys, key)
	}
	sort.Strings(keys)

	result := make([]string, 0, len(keys))
	for _, key := range keys {
		result = append(result, key+"="+extraEnv[key])
	}
	return result
}

func sanitizeDockerEnv(extraEnv map[string]string) map[string]string {
	env := map[string]string{}
	for key, value := range extraEnv {
		env[key] = value
	}

	pathEntries := append([]string{}, defaultContainerPATH...)
	if rawPath := strings.TrimSpace(env["PATH"]); rawPath != "" {
		for _, part := range filepath.SplitList(rawPath) {
			part = strings.TrimSpace(part)
			if part == "" || !filepath.IsAbs(part) {
				continue
			}
			pathEntries = append(pathEntries, part)
		}
	}
	env["PATH"] = joinUniquePaths(pathEntries)
	return env
}

func joinUniquePaths(entries []string) string {
	seen := map[string]struct{}{}
	result := make([]string, 0, len(entries))
	for _, entry := range entries {
		entry = strings.TrimSpace(entry)
		if entry == "" {
			continue
		}
		if _, exists := seen[entry]; exists {
			continue
		}
		seen[entry] = struct{}{}
		result = append(result, entry)
	}
	return strings.Join(result, string(os.PathListSeparator))
}

